"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[764],{7764:function(e,t,a){a.d(t,{JM:function(){return i},Vh:function(){return r},ch:function(){return n},tx:function(){return o},z2:function(){return s}});let i=[{name:"New accounts",logic:"signup_date within last 1 day AND lifetime_downloads = 0",usedBy:"Flow 1"},{name:"Not activated",logic:"account age > 2 days AND first_download_date is empty",usedBy:"Flow 1 recovery"},{name:"Trial — active",logic:"account_type = trial AND trial_end_date in the future",usedBy:"Flow 2A"},{name:"Trial — ending",logic:"account_type = trial AND trial_end_date within 3 days",usedBy:"Flow 2A"},{name:"Trial — expired",logic:"account_type = trial-expired AND trial_end_date in last 14 days",usedBy:"Flow 2A"},{name:"Heavy credit buyer",logic:"account_type = credit_only AND downloads_last_30d ≥ 8",usedBy:"Flow 2B"},{name:"Low credit balance",logic:"credit_balance ≤ 5 AND credit_balance > 0",usedBy:"Flow 2C"},{name:"Out of credits",logic:"credit_balance = 0 AND last_credit_purchase_date is set",usedBy:"Flow 2C"},{name:"Renewal approaching",logic:"subscription_renewal_date within 30 days (annual) / 7 (monthly)",usedBy:"Flow 2D"},{name:"Payment failed",logic:"payment_failed_flag = true",usedBy:"Flow 2D dunning"},{name:"Dormant subscriber",logic:"account_type in (subscriber, hybrid) AND last_login_date > 30 days ago",usedBy:"Flow 3A"},{name:"Churned",logic:"account_type = churned OR subscription_canceled_date is set",usedBy:"Flow 3B"},{name:"Unengaged",logic:"no email open in 180 days",usedBy:"Flow 3C sunset"},{name:"By asset interest",logic:"primary_asset_interest = photos | illustrations | video | icons | templates",usedBy:"Flow 4 personalisation"}],o=[{id:"flow-1",number:"1",title:"Onboarding & Activation",job:"Activate",summary:"Drive every new account to its first meaningful download (activation) and seed core habits: search, Collections, the DAM.",trigger:"account_created → contact enters the “New accounts” segment.",audience:"account_type = trial OR free.",cadence:"6 emails over ~9 days.",exit:"subscription_started → exit; OR trial_end_date within 7 days → hand off to Flow 2A; OR series completes.",delivery:"Marketing Automation (segment-entry). Emails 2 and 6 gate on first_download_date being empty.",suppression:"Product onboarding.",primaryKpi:"Activation rate (first download)",benchmark:"35–50%",emails:[{id:"1.1",title:"Welcome",trigger:"Immediately on account_created.",audience:"All new accounts.",subject:"Welcome to Colourbox/Skyfish — let’s find your first perfect asset",preheader:"Your library of millions of assets is ready. Here’s the fastest way in.",body:"Hi {{first_name}}, welcome aboard. You now have the full Colourbox/Skyfish library at your fingertips — photos, illustrations, video and more, all licensed and ready to use.\n\nThe fastest way to see what Colourbox/Skyfish can do is to run one search for something you actually need this week. Specific terms beat broad ones — try “team meeting candid” rather than “business”.",cta:"Start searching"},{id:"1.2",title:"Activation nudge",trigger:"Day 1 — only if first_download_date is empty.",audience:"New accounts, not yet activated.",subject:"Your first download — here’s how (it takes 20 seconds)",preheader:"Find it, download it, use it. No attribution headaches.",body:"Hi {{first_name}}, we noticed you haven’t grabbed your first asset yet — here’s all there is to it: search, click an asset you like, hit Download. The licence is included, so you’re cleared to use it the moment it lands.\n\nNot sure where to start? These trending collections are a good first stop.",cta:"Browse trending assets"},{id:"1.3",title:"Feature spotlight — Collections",trigger:"Day 3.",audience:"All new accounts.",subject:"The trick agencies use to never lose an asset again",preheader:"Collections turn a messy downloads folder into an organised library.",body:"Hi {{first_name}}, every asset you save into a Collection stays organised, searchable and shareable — no more digging through a downloads folder for “that one image”.\n\nStart one for your current project. Future you will thank you.",cta:"Create your first collection"},{id:"1.4",title:"Feature spotlight — the DAM",trigger:"Day 5.",audience:"All new accounts.",subject:"Stop emailing files around",preheader:"Versioning, sharing and brand folders — your assets in one place.",body:"Hi {{first_name}}, Colourbox/Skyfish isn’t just a stock library — it’s where your team’s assets live. Upload your own files alongside licensed ones, keep versions straight, and share a link instead of a 40 MB attachment.\n\n{{#if is_team_admin}}Invite your team so everyone works from the same source of truth.{{else}}Ask your admin about team folders — or explore what’s already there.{{/if}}",cta:"Explore your asset library"},{id:"1.5",title:"Social proof & use cases",trigger:"Day 7.",audience:"All new accounts.",subject:"How teams like yours get a week back every month",preheader:"Real workflows, from first search to finished campaign.",body:"Hi {{first_name}}, the customers who get the most from Colourbox/Skyfish treat it as step one of every creative task — moodboard in Collections, license in a click, hand off with a share link.\n\nHere’s how three different teams put it to work.",cta:"See Colourbox/Skyfish in action"},{id:"1.6",title:"Activation recovery",trigger:"Day 9 — only if first_download_date is still empty.",audience:"New accounts, never activated.",subject:"Did something get in the way?",preheader:"A quick hand to get you to your first download.",body:"Hi {{first_name}}, you signed up but haven’t downloaded anything yet — that’s completely fine, but we’d love to know if something tripped you up.\n\nReply to this email and a real person will help, or jump straight to a starter pack we’ve put together for new accounts.",cta:"Get the starter pack",notes:"If still not activated 3 days after this email, exit to Flow 2A (if trial) or the Flow 4B newsletter cadence (if free)."}]},{id:"flow-2",number:"2",title:"Trial & Subscription Conversion",job:"Convert",summary:"Four sub-flows turn intent into payment: trials into subscriptions, frequent credit buyers into subscribers, low balances into top-ups, and renewals into retained revenue — including a dunning sequence.",trigger:"Multiple — trial start, credit usage, renewal nearing, payment failed.",audience:"Trials, credit buyers, subscribers.",cadence:"18 emails across 4 sub-flows.",exit:"Per sub-flow — see below.",delivery:"Mix of Marketing Automation and event-triggered API sends.",suppression:"Billing & account, Offers & promotions.",primaryKpi:"Trial→paid %, dunning recovery %",benchmark:"15–25% / 40–60%",subflows:[{id:"2A",title:"2A \xb7 Trial-to-paid",description:"Assumes a 14-day trial. A usage-aware countdown: show people what they’ve already done, then what they’d lose. 3 emails during the trial, 3 after expiry.",emails:[{id:"2A.1",title:"Mid-trial value recap",trigger:"Day 7 of trial.",audience:"Active trials.",subject:"You’ve downloaded {{downloads_last_30d}} assets — here’s what a plan unlocks",preheader:"A quick look at your trial so far.",body:"Hi {{first_name}}, one week into your trial and you’ve already pulled {{downloads_last_30d}} assets and started {{saved_collections_count}} collection(s). Nice work.\n\nOn a plan, that just keeps going — unlimited downloads, the full library, and every collection you’ve built stays exactly where it is. Here’s how the plans compare.",cta:"See plans & pricing"},{id:"2A.2",title:"Trial ending — 3 days left",trigger:"3 days before trial_end_date.",audience:"Active trials.",subject:"3 days left — your collections are about to lock",preheader:"Keep your library, licences and collections running.",body:"Hi {{first_name}}, your trial ends on {{trial_end_date}}. When it does, your collections and download history are saved — but you’ll need a plan to keep downloading and to keep new licences valid.\n\nPick the plan that fits and there’s zero interruption.",cta:"Choose your plan"},{id:"2A.3",title:"Trial ending — last day",trigger:"1 day before trial_end_date.",audience:"Active trials.",subject:"Your trial ends tomorrow, {{first_name}}",preheader:"Two minutes to keep everything running.",body:"This is the last reminder — your Colourbox/Skyfish trial ends tomorrow. Everything you’ve set up stays intact if you pick a plan today.\n\nNot ready for a subscription? A credit pack keeps you downloading with no monthly commitment.",cta:"Keep my account active",notes:"Two CTAs allowed here only — plan (primary button) and credit pack (secondary text link)."},{id:"2A.4",title:"Trial expired",trigger:"Day +1 after trial_end_date.",audience:"account_type = trial-expired.",subject:"Your trial’s done — your collections are safe (for now)",preheader:"Here’s how to pick up where you left off.",body:"Hi {{first_name}}, your trial has ended and your account is now on the free tier. Your {{saved_collections_count}} collection(s) and history are still here — but downloading is paused.\n\nTwo ways back in: a subscription for unlimited use, or a credit pack if you just need a few assets.",cta:"Reactivate with a plan"},{id:"2A.5",title:"Post-trial incentive",trigger:"Day +4 after trial_end_date.",audience:"account_type = trial-expired, not converted.",subject:"Still deciding? Here’s 20% off your first month",preheader:"A little nudge to make it easy.",body:"Hi {{first_name}}, no pressure — but if price was the sticking point, here’s 20% off your first month (or first year, if you go annual). The code applies automatically at checkout.\n\nOffer’s good for 7 days.",cta:"Claim 20% off"},{id:"2A.6",title:"Final post-trial",trigger:"Day +10 after trial_end_date.",audience:"account_type = trial-expired, not converted.",subject:"We’ll keep your account warm",preheader:"No more reminders — just so you know where things stand.",body:"Hi {{first_name}}, this is the last you’ll hear from us about your trial. Your collections stay saved, and you’re welcome back any time.\n\nWe’ll switch you to our occasional new-assets email so you can see what’s landing. A credit pack is always the low-commitment way back in.",cta:"Browse credit packs",notes:"On send, move the contact into the Flow 4B newsletter cadence and exit 2A."}]},{id:"2B",title:"2B \xb7 Credit → subscription upsell",description:"Frequent credit buyers are leaving money on the table — and exposed to friction every time they hit zero. This sub-flow makes the maths obvious.",emails:[{id:"2B.1",title:"Cost comparison",trigger:"On segment entry.",audience:"Heavy credit buyers.",subject:"You’ve spent more on credits than a plan would cost",preheader:"The maths, in your favour.",body:"Hi {{first_name}}, you’ve bought {{credits_purchased_lifetime}} credits with us — and at your current pace, a subscription would already have cost you less and given you unlimited downloads.\n\nHere’s the side-by-side for your actual usage.",cta:"See if a plan saves you money"},{id:"2B.2",title:"Beyond cost",trigger:"Day 4.",audience:"Heavy credit buyers, not converted.",subject:"It’s not just cheaper — it’s less friction",preheader:"No more topping up mid-project.",body:"Hi {{first_name}}, past the price: a plan means never hitting zero mid-project, full access to premium collections, and the DAM tools to keep everything organised.\n\nYour credit history and collections carry straight over.",cta:"Switch to a plan"},{id:"2B.3",title:"Switch incentive",trigger:"Day 10.",audience:"Heavy credit buyers, not converted.",subject:"Switch this week, get your first month half price",preheader:"A thank-you for moving up.",body:"Hi {{first_name}}, if a subscription’s been on your mind, here’s a reason to do it now — 50% off your first month when you switch in the next 7 days.\n\nAny unused credits stay on your account as a buffer.",cta:"Switch and save 50%"}]},{id:"2C",title:"2C \xb7 Credit replenishment",description:"Real-time and short. Remove friction before it interrupts a project — and quietly surface the subscription where it would be cheaper.",emails:[{id:"2C.1",title:"Running low",trigger:"On credit_balance ≤ 5 (and > 0).",audience:"Credit buyers with a low balance.",subject:"You’re down to {{credit_balance}} credits",preheader:"Top up before your next project stalls.",body:"Hi {{first_name}}, heads up — you’ve got {{credit_balance}} credits left. Topping up now means no interruption next time you find the perfect asset.\n\nBigger packs carry a better per-credit rate, if you know more work’s coming.",cta:"Top up credits"},{id:"2C.2",title:"Out of credits",trigger:"On credit_balance = 0.",audience:"Credit buyers at zero balance.",subject:"You’re out of credits — here’s the 30-second fix",preheader:"Plus: a plan might make more sense now.",body:"Hi {{first_name}}, your balance just hit zero. Grab a pack and you’re downloading again immediately.\n\nBuying packs regularly? A subscription is usually cheaper and never runs out — worth a look.",cta:"Buy a credit pack",notes:"If the contact also matches “Heavy credit buyer”, prefer Flow 2B — frequency cap prevents overlap."}]},{id:"2D",title:"2D \xb7 Renewal protection & failed-payment recovery",description:"Two tracks: the renewal track reframes the bill as a value recap; the dunning track recovers failed payments over 10 days before an account pauses. Dunning emails are account-critical and bypass marketing opt-out.",emails:[{id:"2D.1",title:"Renewal heads-up",trigger:"30 days before renewal (annual) / 7 days (monthly).",audience:"Subscribers approaching renewal.",subject:"Your year with Colourbox/Skyfish: {{lifetime_downloads}} downloads and counting",preheader:"Your plan renews on {{subscription_renewal_date}}.",body:"Hi {{first_name}}, your plan renews on {{subscription_renewal_date}} — nothing for you to do, but here’s what it’s covered: {{lifetime_downloads}} downloads, {{saved_collections_count}} collections, and a licence on every one of them.\n\nPlenty more landing this year too. Here’s a peek at what’s coming.",cta:"See what’s new"},{id:"2D.2",title:"At-risk renewal reminder",trigger:"7 days before renewal — only if downloads_last_30d below threshold.",audience:"At-risk subscribers approaching renewal.",subject:"Your plan renews in 7 days — let’s make it count",preheader:"A few things you might have missed.",body:"Hi {{first_name}}, your renewal lands on {{subscription_renewal_date}}. We noticed it’s been a while since you downloaded — here are a few collections worth a look before then.\n\nQuestions about your plan? Just reply.",cta:"Jump back in"},{id:"2D.3",title:"Renewal confirmation",trigger:"On subscription_renewed.",audience:"Renewed subscribers.",subject:"You’re all set for another {{billing_cycle}}",preheader:"Thanks for staying with Colourbox/Skyfish.",body:"Hi {{first_name}}, your plan just renewed — thank you. Everything continues exactly as it was, collections and all.\n\nHere’s what’s new since you started.",cta:"Explore what’s new"},{id:"2D.4",title:"Payment failed — Day 0",trigger:"Immediately on payment_failed.",audience:"Subscribers with a failed payment.",subject:"We couldn’t process your payment",preheader:"A quick card update keeps everything running.",body:"Hi {{first_name}}, your most recent payment didn’t go through — usually an expired card or a temporary bank block. Your account is still active for now.\n\nUpdating your details takes about a minute.",cta:"Update payment details"},{id:"2D.5",title:"Payment failed — Day 3",trigger:"Day 3 — if payment_failed_flag still true.",audience:"Subscribers, payment still failing.",subject:"Still need a hand with your payment?",preheader:"We’ll retry automatically once your card’s updated.",body:"Hi {{first_name}}, just a reminder — we haven’t been able to process your payment yet. Update your card and we’ll retry straight away, with no interruption.",cta:"Fix my payment"},{id:"2D.6",title:"Payment failed — Day 7",trigger:"Day 7 — if payment_failed_flag still true.",audience:"Subscribers, payment still failing.",subject:"Your account pauses in 3 days",preheader:"Last chance to keep things uninterrupted.",body:"Hi {{first_name}}, we’ve tried a few times now. If we can’t process payment in the next 3 days, your account will pause — downloads off, collections saved.\n\nOne quick update avoids all of it.",cta:"Update payment now"},{id:"2D.7",title:"Account paused — Day 10",trigger:"Day 10 — if payment_failed_flag still true.",audience:"Subscribers, payment unrecovered.",subject:"Your account is paused — reactivate any time",preheader:"Your collections are safe. Reactivation takes one click.",body:"Hi {{first_name}}, your account is now paused because we couldn’t process payment. Nothing’s lost — your collections and history are exactly where you left them.\n\nUpdate your card and you’re back instantly.",cta:"Reactivate my account"}]}]},{id:"flow-3",number:"3",title:"Re-engagement & Win-back",job:"Reactivate",summary:"Three sub-flows that catch customers at three different distances: the paying subscriber who has gone quiet, the customer who has churned, and the contact who no longer opens anything.",trigger:"Dormancy, cancellation, or 180 days without an open.",audience:"Subscribers, churned, unengaged.",cadence:"8 emails across 3 sub-flows.",exit:"Login, repurchase, or any open / click.",delivery:"Marketing Automation + event-triggered API send.",suppression:"New assets & inspiration, Offers & promotions.",primaryKpi:"Reactivation rate",benchmark:"10–20% / 5–12%",subflows:[{id:"3A",title:"3A \xb7 Dormant subscriber rescue",description:"Most valuable re-engagement work: a paying-but-idle subscriber is a cancellation waiting to happen. Catch them before renewal.",emails:[{id:"3A.1",title:"We miss you + what’s new",trigger:"On entering the Dormant subscriber segment (~30 days idle).",audience:"Dormant subscribers.",subject:"{{new_asset_count}} new {{primary_asset_interest}} assets since you last visited",preheader:"Your plan’s been busy even if you haven’t.",body:"Hi {{first_name}}, it’s been a few weeks — and your library’s grown. There are fresh {{primary_asset_interest}} assets waiting that match what you usually download.",cta:"See what’s new"},{id:"3A.2",title:"Make your plan pay for itself",trigger:"Day 45 idle.",audience:"Still-dormant subscribers.",subject:"Your plan includes unlimited downloads — let’s use them",preheader:"You’re paying for it; here’s how to get the value back.",body:"Hi {{first_name}}, a quick nudge: your subscription gives you unlimited downloads and full access to every collection. Right now it’s sitting idle.\n\nHere’s a shortlist to make your next project faster.",cta:"Browse curated picks"},{id:"3A.3",title:"Feedback ask",trigger:"Day 60 idle.",audience:"Still-dormant subscribers.",subject:"Is Colourbox/Skyfish still working for you?",preheader:"One question — honestly, we want to know.",body:"Hi {{first_name}}, we’d rather hear it from you than guess. Is Colourbox/Skyfish still pulling its weight? One click below tells us where you’re at — and if something’s off, we’ll personally help sort it.",cta:"Tell us in one click",notes:"If still dormant 14 days after this email, flag the account for CS outreach ahead of renewal."}]},{id:"3B",title:"3B \xb7 Lapsed / churned win-back",description:"A 45-day window while collections are still saved and the relationship is warm. Lead with what changed, then make the offer, then ask why.",emails:[{id:"3B.1",title:"What’s changed",trigger:"Day 14 after churn.",audience:"Recently churned contacts.",subject:"We’ve added a lot since you left",preheader:"No pitch yet — just what’s new.",body:"Hi {{first_name}}, since you’ve been gone, the library’s grown and we’ve shipped a few things customers asked for. No hard sell here — we just thought you’d want to see.",cta:"See what’s new"},{id:"3B.2",title:"Win-back offer",trigger:"Day 30 after churn.",audience:"Churned, not yet returned.",subject:"Come back for 30% off — or just grab a credit pack",preheader:"Two easy ways back in.",body:"Hi {{first_name}}, if you’ve been meaning to come back, here’s a reason: 30% off your first month on any plan. Your old collections are still saved and waiting.\n\nNot ready to commit? A credit pack gets you what you need with no strings.",cta:"Reactivate at 30% off"},{id:"3B.3",title:"Last call + feedback",trigger:"Day 45 after churn.",audience:"Churned, not yet returned.",subject:"Before we say goodbye",preheader:"One question, and a final offer.",body:"Hi {{first_name}}, we won’t keep emailing — but before we go quiet, two things: one quick question on why you left (it genuinely shapes what we build), and the 30% offer is open for 48 more hours.",cta:"Tell us why — and reactivate"}]},{id:"3C",title:"3C \xb7 List hygiene & sunset",description:"Unglamorous, essential. Re-confirming or retiring contacts who never open protects the sender reputation every other flow depends on.",emails:[{id:"3C.1",title:"Re-permission",trigger:"On entering the Unengaged segment.",audience:"Unengaged contacts.",subject:"Do you still want to hear from us?",preheader:"We’ll only keep emailing if you say yes.",body:"Hi {{first_name}}, we noticed you haven’t opened our emails in a while — no problem at all. If you’d still like Colourbox/Skyfish updates, just click below to stay subscribed.\n\nIf not, you don’t need to do anything — we’ll stop, and your inbox stays clean.",cta:"Yes, keep me subscribed"},{id:"3C.2",title:"Final notice",trigger:"Day 10 — if no open/click on Email 3C.1.",audience:"Still-unengaged contacts.",subject:"Last email — unless you tell us otherwise",preheader:"We’re cleaning house. Here’s how to stay.",body:"Hi {{first_name}}, this is the last email we’ll send unless you confirm you want to stay. One click keeps you in; silence moves you out. Either way, no hard feelings.",cta:"Keep me on the list",notes:"Non-responders after this email: suppress from all marketing sends. Protects sender reputation."}]}]},{id:"flow-4",number:"4",title:"Behavioural & Promotional",job:"Convert",summary:"Real-time reactions to on-site behaviour, plus the planned promotional calendar. Highest revenue-per-email because they reach people at the exact moment of intent.",trigger:"Real-time on-site behaviour + scheduled broadcasts.",audience:"All active accounts.",cadence:"7 emails + seasonal calendar.",exit:"Download / licence event (or n/a for ongoing flows).",delivery:"Mostly event-triggered API sends.",suppression:"New assets & inspiration, Offers & promotions.",primaryKpi:"Revenue per email",benchmark:"10–20% (abandonment)",subflows:[{id:"4A",title:"4A \xb7 Search & collection abandonment",description:"Convert active intent — a search or a curated collection — into a download or licence.",emails:[{id:"4A.1",title:"Search abandonment",trigger:"48h after search_performed with no download.",audience:"Active accounts with an abandoned search.",subject:"Still looking for “{{last_search_term}}”?",preheader:"A few picks you might have missed.",body:"Hi {{first_name}}, you searched for “{{last_search_term}}” the other day but didn’t grab anything — it happens. Here are some strong matches, plus a few fresh angles on the same idea.",cta:"See these picks"},{id:"4A.2",title:"Collection abandonment",trigger:"5 days after collection activity with no licence.",audience:"Active accounts with an unlicensed collection.",subject:"Your collection is ready when you are",preheader:"{{saved_collections_count}} collection(s) waiting on you.",body:"Hi {{first_name}}, you’ve curated some great assets into a collection but haven’t downloaded them yet. Whenever the project’s ready, they’re one click from licensed.",cta:"Open my collection"}]},{id:"4B",title:"4B \xb7 New-asset alerts",description:"The “home” cadence — a genuinely useful weekly email that keeps Colourbox/Skyfish top-of-mind.",emails:[{id:"4B.1",title:"Weekly new assets",trigger:"Weekly, fixed day/time per locale.",audience:"Marketing-permitted contacts, by asset interest.",subject:"This week in {{primary_asset_interest}}: {{new_asset_count}} new picks",preheader:"Fresh to your library — curated for what you download.",body:"Hi {{first_name}}, here’s what’s new in {{primary_asset_interest}} this week — hand-picked to match what you actually use.\n\n{{#each new_assets}} {{this.title}} {{/each}}",cta:"Browse this week’s new assets"}]},{id:"4C",title:"4C \xb7 Browse abandonment",description:"Recover high-intent browsers who looked but didn’t download.",emails:[{id:"4C.1",title:"Browse abandonment",trigger:"72h after asset-detail views with no download.",audience:"Active accounts with an abandoned browse.",subject:"That asset you were eyeing — plus 5 like it",preheader:"Picking up where you left off.",body:"Hi {{first_name}}, you took a close look at a few assets but didn’t download — here’s the one you spent longest on, plus five close matches in case it wasn’t quite right.",cta:"View these assets"}]},{id:"4D",title:"4D \xb7 Post-download cross-sell",description:"Increase assets per session and reinforce the download habit.",emails:[{id:"4D.1",title:"Post-download cross-sell",trigger:"A few hours after a download / licence event.",audience:"All active accounts.",subject:"Nice pick — here’s what pairs well",preheader:"Assets that work alongside your last download.",body:"Hi {{first_name}}, great choice on your last download. Projects rarely need just one asset, so here’s a set that pairs naturally with it — same style, same shoot, or a matching series.",cta:"See matching assets",notes:"Branch on account_type: for credit buyers, add a soft line on bulk packs; for subscribers, nudge Collections."}]},{id:"4F",title:"4F \xb7 Milestone celebration",description:"Reinforce loyalty at natural high points and open a referral ask.",emails:[{id:"4F.1",title:"Milestone celebration",trigger:"On milestone_reached (lifetime_downloads crosses 50 / 100 / 500).",audience:"Accounts crossing a download milestone.",subject:"You’ve downloaded {{lifetime_downloads}} assets with Colourbox/Skyfish",preheader:"A small thank-you for a big number.",body:"Hi {{first_name}}, you just crossed {{lifetime_downloads}} downloads — that’s a serious body of work. Thank you for building it with us.\n\nHere’s a little something: bonus credits on your account. And if you know someone who’d love Colourbox/Skyfish, there’s a referral perk below for both of you.",cta:"Share Colourbox/Skyfish, get credits"}]},{id:"4G",title:"4G \xb7 Referral",description:"Turn happy power users into an acquisition channel.",emails:[{id:"4G.1",title:"Referral invite",trigger:"On high-engagement segment entry, or post-milestone.",audience:"Engaged power users.",subject:"Give a friend credits, get credits yourself",preheader:"Your referral link, ready to share.",body:"Hi {{first_name}}, you clearly get a lot out of Colourbox/Skyfish — so here’s the deal: share your link, your friend gets bonus credits on signup, and you get the same when they do.\n\nNo limit on how many friends you invite. Your link’s below.",cta:"Get my referral link"}]}]}],n=[{name:"Product onboarding",contents:"Flow 1 — welcome and activation emails.",default:"Opt-in"},{name:"New assets & inspiration",contents:"Flow 4B newsletter, abandonment, cross-sell, milestones.",default:"Opt-in"},{name:"Offers & promotions",contents:"Incentives, win-back offers, referral, upsell.",default:"Opt-in"},{name:"Billing & account",contents:"Trial expiry, dunning, renewal, credit balance. Account-critical.",default:"Always on"}];function r(e){var t;return e.emails?e.emails:(null!==(t=e.subflows)&&void 0!==t?t:[]).flatMap(e=>e.emails.map(t=>({...t,subflowTitle:e.title})))}function s(e){for(let t of o){let a=r(t).find(t=>t.id===e);if(a)return{flow:t,email:a,subflowTitle:a.subflowTitle}}return null}}}]);